import React, { useState, useEffect } from "react";
import { Layers, Hash, Save, CheckSquare, Square, Loader2, Edit, Trash2, Search, XCircle } from "lucide-react";
import axios from "../api/axios";
import toast from "react-hot-toast";

const CategoryMaster = () => {
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  
  const [formData, setFormData] = useState({ catId: "", examId: "", catName: "", features: [] });
  const options = ["SYLLABUS", "MOCK TEST", "PYQ", "STUDY MATERIAL", "VIDEOS"];

  const fetchData = async () => {
    setLoading(true);
    try {
      const [exRes, catRes, idRes] = await Promise.all([
        axios.get("/master/exam/all"),
        axios.get("/master/category/all"),
        axios.get("/master/category/next-id")
      ]);

      if (exRes.data.success) setExams(exRes.data.data);
      if (catRes.data.success) setCategories(catRes.data.data);
      if (idRes.data.success && !editId) {
        setFormData(prev => ({ ...prev, catId: idRes.data.nextId }));
      }
    } catch (err) {
      console.error("SYNC ERROR:", err);
      toast.error("DATABASE SYNC FAILED");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);


  // Add this function to fix the 'handleEdit is not defined' error
  const handleEdit = (cat) => {
    setEditId(cat._id);
    setFormData({
      catId: cat.catId,
      // We check if examId exists and use its _id for the dropdown
      examId: cat.examId?._id || "", 
      catName: cat.catName,
      features: cat.features || []
    });
    // Smoothly scroll to the top of the form for editing
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };
  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const res = await axios.post("/master/category/upsert", { id: editId, ...formData });
      if (res.data.success) {
        toast.success(editId ? "UPDATED" : "SAVED");
        setEditId(null);
        setFormData({ catId: "", examId: "", catName: "", features: [] });
        fetchData();
      }
    } catch { toast.error("SAVE FAILED"); }
    finally { setIsSaving(false); }
  };

  const filtered = categories.filter(c => 
    c.catName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.examId?.examName?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 max-w-6xl mx-auto space-y-8">
      {/* FORM SECTION */}
      <form onSubmit={handleSubmit} className="bg-white rounded-[32px] p-8 shadow-xl border border-slate-100">
        <h1 className="text-2xl font-black mb-8 uppercase flex justify-between items-center">
          <span className="flex items-center gap-3"><Layers className="text-blue-600" /> Category Master</span>
          {editId && <button type="button" onClick={() => {setEditId(null); fetchData();}} className="text-xs text-red-500 uppercase"><XCircle size={14} /> Cancel</button>}
        </h1>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Category ID</label>
            <div className="p-4 bg-slate-50 rounded-2xl font-bold text-blue-600 border border-slate-100 flex items-center gap-2">
              <Hash size={14} /> {formData.catId || "LOADING..."}
            </div>
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Parent Exam</label>
            <select 
              className="w-full p-4 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600 uppercase transition-all"
              value={formData.examId} 
              onChange={(e) => setFormData({...formData, examId: e.target.value})} 
              required
            >
              <option value="">-- CHOOSE --</option>
              {exams.map(ex => <option key={ex._id} value={ex._id}>{ex.examName}</option>)}
            </select>
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Category Name</label>
            <input 
              type="text" required
              className="w-full p-4 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600 uppercase transition-all"
              value={formData.catName} 
              onChange={(e) => setFormData({...formData, catName: e.target.value.toUpperCase()})} 
              placeholder="e.g. NTPC" 
            />
          </div>
        </div>

        <div className="mb-8 p-6 bg-slate-50 rounded-2xl">
          <label className="text-[10px] font-black uppercase text-slate-400 mb-4 block">Enabled Features</label>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            {options.map(opt => (
              <button 
                key={opt} type="button" 
                onClick={() => setFormData(prev => ({ ...prev, features: prev.features.includes(opt) ? prev.features.filter(i => i !== opt) : [...prev.features, opt] }))} 
                className={`flex items-center gap-2 p-3 rounded-xl border-2 transition-all font-black text-[9px] ${formData.features.includes(opt) ? "bg-blue-600 border-blue-600 text-white shadow-lg" : "bg-white border-slate-100 text-slate-400"}`}
              >
                {formData.features.includes(opt) ? <CheckSquare size={14}/> : <Square size={14}/>} {opt}
              </button>
            ))}
          </div>
        </div>

        <button disabled={isSaving} className="w-full py-4 bg-[#0F172A] text-white rounded-2xl font-black uppercase tracking-widest hover:bg-blue-600 transition-all flex justify-center items-center gap-2">
          {isSaving ? <Loader2 className="animate-spin" /> : <Save size={20} />} {editId ? "Update Record" : "Save Record"}
        </button>
      </form>

      {/* TABLE SECTION */}
      <div className="bg-white rounded-[32px] shadow-xl border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-50 flex flex-col md:flex-row justify-between items-center gap-4">
          <h2 className="font-black uppercase tracking-tighter text-slate-800">Category List</h2>
          <div className="relative w-full md:w-72">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input type="text" placeholder="Search..." className="w-full pl-10 pr-4 py-2 bg-slate-50 rounded-xl text-xs font-bold outline-none uppercase" onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest">
                <th className="p-4">ID</th>
                <th className="p-4">Exam</th>
                <th className="p-4">Category</th>
                <th className="p-4">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filtered.map(cat => (
                <tr key={cat._id} className="text-xs font-bold text-slate-600 hover:bg-slate-50 transition-all">
                  <td className="p-4 text-blue-600">{cat.catId}</td>
                  <td className="p-4 uppercase">{cat.examId?.examName || "ERR"}</td>
                  <td className="p-4 uppercase text-slate-900">{cat.catName}</td>
                  <td className="p-4 flex gap-2">
                    <button onClick={() => handleEdit(cat)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white"><Edit size={14}/></button>
                    <button onClick={() => { if(window.confirm("Delete?")) axios.delete(`/master/category/${cat._id}`).then(() => fetchData()) }} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-500 hover:text-white"><Trash2 size={14}/></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CategoryMaster;
